INSERT INTO tracks (id, name, description) VALUES ('00000000-0000-0000-0000-000000000001', 'RAG Systems', 'Build production-grade retrieval-augmented generation pipelines') ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('0bd6c71b-9c8b-49e9-8124-a2b2d4cb35cc', '00000000-0000-0000-0000-000000000001', 0, 'CONCEPT', '{"Google","OpenAI"}', '{"content":"# Introduction to RAG\n\nRetrieval-Augmented Generation (RAG) combines a retrieval step with a generative model.\n\n## How it works\n\n1. User submits a query\n2. A vector search retrieves relevant document chunks\n3. The chunks are passed as context to the LLM\n4. The LLM generates a grounded answer\n\n## Why chunk size matters\n\nSmaller chunks improve precision but increase retrieval latency. Larger chunks reduce calls but may include irrelevant context.","pro_tip":"Start with chunk sizes between 256-512 tokens. Smaller chunks improve precision; larger chunks improve context retention.","resources":[{"type":"article","label":"RAG Overview Paper"},{"type":"read","label":"Vector Store Comparison"},{"type":"quiz","label":"Comprehension Quiz"}],"difficulty":"Intermediate","learning_objectives":["Understand RAG architecture and retrieval flow","Configure vector similarity search thresholds","Evaluate chunk size impact on retrieval quality"],"estimated_duration_minutes":45}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('81dbf2d1-2dd3-43f7-bdc0-08454482e951', '00000000-0000-0000-0000-000000000001', 0, 'CODING', '{"Anthropic"}', '{"difficulty":"Advanced","description":"Implement a chunking strategy that splits text on sentence boundaries.","starter_files":[{"name":"main.py","content":"# Implement chunk_text(text: str, chunk_size: int) -> list[str]\n"},{"name":"utils.py","content":"# Helper utilities\n"}],"estimated_duration_minutes":90}'::jsonb) ON CONFLICT (id) DO NOTHING;
INSERT INTO modules (id, track_id, stage_index, tier_type, company_tags, content_payload) VALUES ('53f5aef9-97e7-490f-b723-a6948c0cee7f', '00000000-0000-0000-0000-000000000001', 1, 'SIMULATOR', '{"Pinecone","Weaviate"}', '{"pro_tip":"Watch the cache hit ratio — enabling semantic caching dramatically reduces token spend.","resources":[{"type":"read","label":"Simulator Guide"}],"difficulty":"Intermediate","description":"Tune your RAG pipeline parameters and observe the effect on retrieval latency and cost.","learning_objectives":["Tune chunk size and overlap for optimal retrieval","Observe latency vs quality trade-offs in real-time","Understand the impact of cache on token spend"],"estimated_duration_minutes":60}'::jsonb) ON CONFLICT (id) DO NOTHING;
